-- Canonical seed: paste and run this entire file in Supabase → SQL Editor.
-- Roster matches references/Global Master List - MASTERLIST.csv (789 rows, batch 1).
--
-- Adds import_batch_id / source_file if missing (IF NOT EXISTS), truncates the table
-- (all rows + identity reset), then inserts ~789 rows. If TRUNCATE fails on foreign keys,
-- drop or CASCADE those FKs first, or clear child rows then re-run.

BEGIN;

ALTER TABLE public.global_master_list
  ADD COLUMN IF NOT EXISTS import_batch_id bigint,
  ADD COLUMN IF NOT EXISTS source_file text;

CREATE INDEX IF NOT EXISTS global_master_list_import_batch_id_idx
  ON public.global_master_list (import_batch_id DESC);

TRUNCATE TABLE public.global_master_list RESTART IDENTITY;


COMMIT;

-- Row count (should match CSV body rows): 789
